  async importProducts(data) {
    const { products, skipDuplicates = true, updateExisting = false } = data;
    const results = {
      created: 0,
      updated: 0,
      skipped: 0,
      errors: []
    };
    for (const productData of products) {
      try {
        const sku = productData.sku || await this.generateUniqueSku();
        const existing = await db_default.product.findFirst({
          where: {
            name: productData.name,
            categoryId: productData.categoryId,
            deletedAt: null
          }
        });
        if (existing) {
          if (updateExisting) {
            const { sku: _importSku, ...updatePayload } = productData;
            await db_default.product.update({
              where: { id: existing.id },
              data: { ...updatePayload, tags: [] }
            });
            results.updated++;
          } else if (skipDuplicates) {
            results.skipped++;
          } else {
            throw new Error(`Product "${productData.name}" already exists`);
          }
        } else {
          await db_default.product.create({
            data: {
              ...productData,
              sku: sku.toUpperCase(),
              tags: [],
              stockCount: 0
            }
          });
          results.created++;
        }
      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : "Unknown error";
        results.errors.push(`Failed to import "${productData.name}": ${errorMessage}`);
      }
    }
    return results;
  }
