var EmailTemplateService = class {
  // ================================
  // CRUD OPERATIONS
  // ================================
  async create(data) {
    const emailTemplate = await db3.emailTemplate.create({
      data
    });
    return emailTemplate;
  }
  async findById(id) {
    const emailTemplate = await db3.emailTemplate.findUnique({
      where: { id }
    });
    if (!emailTemplate) {
      throw new Error("Email template not found");
    }
    return emailTemplate;
  }
  async findMany(query) {
    const { page, limit, type, search } = query;
    const skip = (page - 1) * limit;
    const where = {};
    if (type) {
      where.type = { contains: type, mode: "insensitive" };
    }
    if (search) {
      where.OR = [
        { type: { contains: search, mode: "insensitive" } },
        { subject: { contains: search, mode: "insensitive" } }
      ];
    }
    const [emailTemplates, total] = await Promise.all([
      db3.emailTemplate.findMany({
        where,
        skip,
        take: limit,
        orderBy: { id: "desc" }
      }),
      db3.emailTemplate.count({ where })
    ]);
    return {
      data: emailTemplates,
      meta: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
        hasNextPage: page < Math.ceil(total / limit),
        hasPrevPage: page > 1
      }
    };
  }
  async update(id, data) {
    await this.findById(id);
    const emailTemplate = await db3.emailTemplate.update({
      where: { id },
      data
    });
    return emailTemplate;
  }
  async delete(id) {
    await this.findById(id);
    await db3.emailTemplate.delete({
      where: { id }
    });
    return { success: true, message: "Email template deleted successfully" };
  }
  // ================================
  // UTILITY METHODS
  // ================================
  async findByType(type) {
    const emailTemplate = await db3.emailTemplate.findFirst({
      where: { type }
    });
    return emailTemplate;
  }
  async getAllTypes() {
    const types = await db3.emailTemplate.findMany({
      select: { type: true },
      distinct: ["type"],
      orderBy: { type: "asc" }
    });
    return types.map((t) => t.type);
  }
};

