init_db();
var NewsletterService = class {
  // ================================
  // PUBLIC OPERATIONS
  // ================================
  async subscribe(email) {
    const existing = await db_default.newsletterSubscriber.findFirst({
      where: { email }
    });
    if (existing) {
      throw new Error("This email is already subscribed to our newsletter");
    }
    const subscriber = await db_default.newsletterSubscriber.create({
      data: { email },
      select: {
        id: true,
        email: true,
        createdAt: true
      }
    });
    return subscriber;
  }
  // ================================
  // ADMIN OPERATIONS
  // ================================
  async findAll(params) {
    const { page = 1, limit = 20, search, sortBy = "createdAt", sortOrder = "desc" } = params;
    const where = {};
    if (search) {
      where.email = {
        contains: search,
        mode: "insensitive"
      };
    }
    const total = await db_default.newsletterSubscriber.count({ where });
    const subscribers = await db_default.newsletterSubscriber.findMany({
      where,
      select: {
        id: true,
        email: true,
        createdAt: true
      },
      orderBy: { [sortBy]: sortOrder },
      skip: (page - 1) * limit,
      take: limit
    });
    return {
      data: subscribers,
      pagination: {
        total,
        page,
        limit,
        pages: Math.ceil(total / limit),
        hasNext: page < Math.ceil(total / limit),
        hasPrev: page > 1
      }
    };
  }
  async delete(id) {
    const subscriber = await db_default.newsletterSubscriber.findUnique({
      where: { id }
    });
    if (!subscriber) {
      throw new Error("Subscriber not found");
    }
    await db_default.newsletterSubscriber.delete({
      where: { id }
    });
  }
};
