var sendOrderOTP = async (req, res) => {
  try {
    const userId = req.user?.userId;
    const userEmail = req.user?.email;
    if (!userId || !userEmail) {
      return res.status(401).json({
        success: false,
        message: "Authentication required"
      });
    }
    const twoMinutesAgo = new Date(Date.now() - 2 * 60 * 1e3);
    const recentOTP = await db_default.oTP.findFirst({
      where: {
        type: "order_verification",
        email: userEmail,
        createdAt: {
          gte: twoMinutesAgo
        }
      },
      orderBy: {
        createdAt: "desc"
      }
    });
    if (recentOTP) {
      const waitTimeSeconds = Math.ceil(
        (recentOTP.createdAt.getTime() + 2 * 60 * 1e3 - Date.now()) / 1e3
      );
      const waitTimeMinutes = Math.ceil(waitTimeSeconds / 60);
      const message = waitTimeSeconds >= 60 ? `Please wait ${waitTimeMinutes} minute${waitTimeMinutes > 1 ? "s" : ""} before requesting a new OTP` : `Please wait ${waitTimeSeconds} seconds before requesting a new OTP`;
      return res.status(429).json({
        success: false,
        message
      });
    }
    const otp = Math.floor(1e5 + Math.random() * 9e5).toString();
    const expiresAt = new Date(Date.now() + 10 * 60 * 1e3);
    await db_default.oTP.create({
      data: {
        type: "order_verification",
        otp,
        email: userEmail,
        expiresAt
      }
    });
    const emailSubject = "Your Order Verification OTP - UHQ Accounts";
    const emailText = `
Hello,

Your OTP for order verification is: ${otp}

This OTP will expire in 10 minutes.
Please do not share this code with anyone.

Best regards,
UHQ Accounts Team
    `.trim();
    await sendEmail(userEmail, emailText, emailSubject);
    res.json({
      success: true,
      message: "OTP sent successfully to your email",
      data: {
        expiresAt
      }
    });
  } catch (error) {
    console.error("Send order OTP error:", error);
    res.status(500).json({
      success: false,
      message: error instanceof Error ? error.message : "Failed to send OTP"
    });
  }
};
