var getStatistics = async (req, res) => {
  try {
    const todayStart = /* @__PURE__ */ new Date();
    todayStart.setHours(0, 0, 0, 0);
    const todayEnd = /* @__PURE__ */ new Date();
    todayEnd.setHours(23, 59, 59, 999);
    const [
      totalPendingOrders,
      totalCompletedOrders,
      totalPartialOrders,
      totalCancelledOrders,
      totalProducts,
      totalCustomers,
      totalBlogs,
      newCustomersToday
    ] = await Promise.all([
      // Total pending orders
      db_default.order.count({
        where: { status: "PENDING" }
      }),
      // Total completed orders
      db_default.order.count({
        where: { status: "COMPLETED" }
      }),
      // Total partial orders
      db_default.order.count({
        where: { status: "PARTIAL" }
      }),
      // Total cancelled orders
      db_default.order.count({
        where: { status: "CANCELLED" }
      }),
      // Total products
      db_default.product.count(),
      // Total customers (exclude guests and admins)
      db_default.user.count({
        where: {
          role: "CUSTOMER",
          isGuest: false
        }
      }),
      // Total blogs
      db_default.blog.count(),
      // New customers today
      db_default.user.count({
        where: {
          role: "CUSTOMER",
          isGuest: false,
          createdAt: {
            gte: todayStart,
            lte: todayEnd
          }
        }
      })
    ]);
    res.json({
      success: true,
      data: {
        orders: {
          pending: totalPendingOrders,
          completed: totalCompletedOrders,
          partial: totalPartialOrders,
          cancelled: totalCancelledOrders,
          total: totalPendingOrders + totalCompletedOrders + totalPartialOrders + totalCancelledOrders
        },
        products: {
          total: totalProducts
        },
        customers: {
          total: totalCustomers,
          newToday: newCustomersToday
        },
        blogs: {
          total: totalBlogs
        }
      },
      message: "Statistics retrieved successfully"
    });
  } catch (error) {
    console.error("Get statistics error:", error);
    res.status(500).json({
      success: false,
      message: error instanceof Error ? error.message : "Failed to retrieve statistics"
    });
  }
};

