// src/services/subscription-package.service.ts
init_db();
init_cache_service();
var SubscriptionPackageService = class {
  CACHE_PREFIX = "uhq:subscription-package:";
  CACHE_TTL = 3600;
  // 1 hour
  // ================================
  // CREATE
  // ================================
  async create(data) {
    const existing = await db_default.subscriptionPackage.findUnique({
      where: { name: data.name }
    });
    if (existing) {
      throw new Error("Subscription package with this name already exists");
    }
    const subscriptionPackage = await db_default.subscriptionPackage.create({
      data: {
        name: data.name,
        description: data.description,
        discount: data.discount,
        price: data.price,
        duration: data.duration,
        isActive: data.isActive,
        meta: data.meta
      }
    });
    await this.invalidateCache();
    return subscriptionPackage;
  }
  // ================================
  // READ
  // ================================
  async findById(id) {
    const cacheKey = `${this.CACHE_PREFIX}${id}`;
    const cached = await cacheService.get(cacheKey);
    if (cached) {
      return cached;
    }
    const subscriptionPackage = await db_default.subscriptionPackage.findUnique({
      where: { id }
    });
    if (!subscriptionPackage) {
      throw new Error("Subscription package not found");
    }
    await cacheService.set(cacheKey, subscriptionPackage, this.CACHE_TTL);
    return subscriptionPackage;
  }
  async findMany(query) {
    const { page, limit, search, isActive, sortBy, sortOrder } = query;
    const where = {};
    if (search) {
      where.name = { contains: search, mode: "insensitive" };
    }
    if (isActive !== void 0) {
      where.isActive = isActive;
    }
    const total = await db_default.subscriptionPackage.count({ where });
    const subscriptionPackages = await db_default.subscriptionPackage.findMany({
      where,
      orderBy: { [sortBy]: sortOrder },
      skip: (page - 1) * limit,
      take: limit
    });
    return {
      data: subscriptionPackages,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
        hasNext: page < Math.ceil(total / limit),
        hasPrev: page > 1
      }
    };
  }
  // ================================
  // UPDATE
  // ================================
  async update(id, data) {
    const existing = await db_default.subscriptionPackage.findUnique({
      where: { id }
    });
    if (!existing) {
      throw new Error("Subscription package not found");
    }
    if (data.name && data.name !== existing.name) {
      const duplicate = await db_default.subscriptionPackage.findUnique({
        where: { name: data.name }
      });
      if (duplicate) {
        throw new Error("Subscription package with this name already exists");
      }
    }
    const subscriptionPackage = await db_default.subscriptionPackage.update({
      where: { id },
      data
    });
    await this.invalidateCache();
    return subscriptionPackage;
  }
  // ================================
  // DELETE
  // ================================
  async delete(id) {
    const existing = await db_default.subscriptionPackage.findUnique({
      where: { id }
    });
    if (!existing) {
      throw new Error("Subscription package not found");
    }
    await db_default.subscriptionPackage.delete({
      where: { id }
    });
    await this.invalidateCache();
    return { message: "Subscription package deleted successfully" };
  }
  // ================================
  // HELPER METHODS
  // ================================
  async invalidateCache() {
    await cacheService.clearPattern(`${this.CACHE_PREFIX}*`);
  }
};

