function generateTxtContentSimple(order, accounts, header, footer) {
  if (order.product.type === "FILE") {
    const lines2 = [header, ""];
    accounts.forEach((file, index) => {
      lines2.push(`${file.fileName || `File ${index + 1}`}: ${file.fileUrl || "N/A"}`);
    });
    lines2.push("", footer);
    return lines2.join("\n");
  }
  const lines = [header, ""];
  for (const acc of accounts) {
    const creds = acc.credentials || acc;
    const login3 = acc.phone || creds.username || creds.id || creds.email || creds.phone || acc.email || acc.username || acc.id || "N/A";
    const pass = acc.password || creds.password || "N/A";
    lines.push(`${login3}:${pass}`);
  }
  lines.push("", footer);
  return lines.join("\n");
}
