var CustomerCreateTicketSchema = import_zod44.z.object({
  orderNumber: import_zod44.z.string().min(1, "Order ID is required").max(100, "Order ID is too long").transform((value) => value.trim().toUpperCase()),
  subject: import_zod44.z.string().min(5, "Subject must be at least 5 characters long").max(255, "Subject must be less than 255 characters"),
  description: import_zod44.z.string().min(20, "Description must be at least 20 characters long").max(5e3, "Description must be less than 5000 characters"),
  attachments: import_zod44.z.array(import_zod44.z.string().url("Invalid attachment URL")).max(10).default([])
});
var createTicket2 = async (req, res) => {
  try {
    const validatedRequest = CustomerCreateTicketSchema.parse(req.body);
    const [user, order] = await Promise.all([
      db_default.user.findUnique({
        where: { id: req.user.userId },
        select: {
          id: true,
          email: true,
          firstName: true,
          phone: true
        }
      }),
      db_default.order.findFirst({
        where: {
          orderNumber: validatedRequest.orderNumber,
          userId: req.user.userId
        },
        select: {
          id: true,
          orderNumber: true,
          status: true,
          deliveryStatus: true,
          total: true,
          quantity: true,
          customerName: true,
          customerPhone: true,
          createdAt: true,
          product: {
            select: {
              id: true,
              name: true,
              sku: true,
              type: true,
              platform: true
            }
          }
        }
      })
    ]);
    if (!order) {
      return handleControllerError(
        res,
        new Error("Order not found for this account"),
        "Order not found for this account"
      );
    }
    const ticketData = {
      subject: validatedRequest.subject,
      description: validatedRequest.description,
      attachments: validatedRequest.attachments,
      userId: req.user.userId,
      meta: {
        orderContext: {
          orderId: order.id,
          orderNumber: order.orderNumber,
          status: order.status,
          deliveryStatus: order.deliveryStatus,
          quantity: order.quantity,
          total: Number(order.total.toString()),
          createdAt: order.createdAt.toISOString(),
          product: order.product,
          client: {
            email: user?.email || req.user.email,
            name: user?.firstName || order.customerName || req.user.email,
            phone: user?.phone || order.customerPhone || null
          }
        }
      }
    };
    const validatedData = CreateTicketSchema.parse(ticketData);
    const ticket = await ticketService2.createTicket(validatedData);
    return sendCreatedResponse(res, ticket, "Ticket created successfully");
  } catch (error) {
    return handleControllerError(res, error, "Failed to create ticket");
  }
};
var closeTicket = async (req, res) => {
  try {
    const { ticketNumber } = req.params;
    const ticket = await ticketService2.getTicketByNumber(ticketNumber);
    if (!ticket || ticket.userId !== req.user.userId) {
      return handleControllerError(res, new Error("Ticket not found"), "Ticket not found");
    }
    const updatedTicket = await ticketService2.updateTicket(ticket.id, { status: "CLOSED" });
    return sendSuccessResponse(res, updatedTicket, "Ticket closed successfully");
  } catch (error) {
    return handleControllerError(res, error, "Failed to close ticket");
  }
};
