var import_express50 = require("express");

// src/controllers/customer/withdrawal.controller.ts
init_db();
init_notification_service();
var notificationService2 = new NotificationService();
var createWithdrawal = async (req, res) => {
  try {
    const userId = req.user?.userId;
    if (!userId) {
      return res.status(401).json({
        success: false,
        message: "User not authenticated"
      });
    }
    const validatedData = CreateWithdrawalSchema.parse(req.body);
    const user = await db_default.user.findUnique({
      where: { id: userId },
      select: {
        balance: true,
        referralEarnings: true,
        email: true,
        firstName: true,
        username: true
      }
    });
    if (!user) {
      return res.status(404).json({
        success: false,
        message: "User not found"
      });
    }
    const source = validatedData.source ?? "balance";
    const amount = validatedData.amount;
    if (source === "referral") {
      const available = Number(user.referralEarnings);
      if (amount > available) {
        return res.status(400).json({
          success: false,
          message: `Insufficient referral earnings. Available: $${available.toFixed(2)}`
        });
      }
    } else if (amount > Number(user.balance)) {
      return res.status(400).json({
        success: false,
        message: `Insufficient balance. Available: $${Number(user.balance).toFixed(2)}`
      });
    }
    const withdrawal = await db_default.$transaction(async (tx) => {
      const createdWithdrawal = await tx.withdrawal.create({
        data: {
          userId,
          amount: validatedData.amount,
          method: validatedData.method,
          status: "PENDING",
          meta: { ...validatedData.meta || {}, source }
        }
      });
      if (source === "referral") {
        await tx.user.update({
          where: { id: userId },
          data: { referralEarnings: { decrement: amount } }
        });
      }
      return createdWithdrawal;
    });
    try {
      const customerName = user.firstName || user.username || user.email;
      await notificationService2.notifyAdminsWithdrawalRequest({
        customerName,
        customerEmail: user.email,
        amount: Number(validatedData.amount),
        method: validatedData.method,
        currentBalance: source === "referral" ? Number(user.referralEarnings) : Number(user.balance),
        withdrawalId: withdrawal.id
      });
      console.log("[Withdrawal] Admin notification sent for withdrawal request", {
        withdrawalId: withdrawal.id,
        userId
      });
    } catch (error) {
      console.error("[Withdrawal] Failed to send admin notification", {
        withdrawalId: withdrawal.id,
        error: error instanceof Error ? error.message : "Unknown error"
      });
    }
    res.status(201).json({
      success: true,
      data: withdrawal,
      message: "Withdrawal request created successfully. Admin will process it soon."
    });
  } catch (error) {
    console.error("Create withdrawal error:", error);
    if (error instanceof Error && error.name === "ZodError") {
      return res.status(400).json({
        success: false,
        message: "Validation failed",
        errors: error
      });
    }
    res.status(500).json({
      success: false,
      message: error instanceof Error ? error.message : "Failed to create withdrawal request"
    });
  }
};
var getWithdrawals2 = async (req, res) => {
  try {
    const userId = req.user?.userId;
    if (!userId) {
      return res.status(401).json({
        success: false,
        message: "User not authenticated"
      });
    }
    const { page = 1, limit = 20, status } = req.query;
    const skip = (Number(page) - 1) * Number(limit);
    const where = { userId };
    if (status && (status === "PENDING" || status === "DONE")) {
      where.status = status;
    }
    const [withdrawals, total] = await Promise.all([
      db_default.withdrawal.findMany({
        where,
        skip,
        take: Number(limit),
        orderBy: { createdAt: "desc" }
      }),
      db_default.withdrawal.count({ where })
    ]);
    res.json({
      success: true,
      data: withdrawals,
      pagination: {
        page,
        limit,
        total,
        pages: Math.ceil(total / Number(limit)),
        hasNext: Number(page) * Number(limit) < total,
        hasPrev: Number(page) > 1
      },
      message: "Withdrawal requests retrieved successfully"
    });
  } catch (error) {
    console.error("Get withdrawals error:", error);
    res.status(500).json({
      success: false,
      message: error instanceof Error ? error.message : "Failed to retrieve withdrawal requests"
    });
  }
};
var getWithdrawalById2 = async (req, res) => {
  try {
    const userId = req.user?.userId;
    const withdrawalId = parseInt(req.params.id);
    if (!userId) {
      return res.status(401).json({
        success: false,
        message: "User not authenticated"
      });
    }
    if (isNaN(withdrawalId)) {
      return res.status(400).json({
        success: false,
        message: "Invalid withdrawal ID"
      });
    }
    const withdrawal = await db_default.withdrawal.findFirst({
      where: {
        id: withdrawalId,
        userId
        // Ensure user can only access their own withdrawals
      }
    });
    if (!withdrawal) {
      return res.status(404).json({
        success: false,
        message: "Withdrawal request not found"
      });
    }
    res.json({
      success: true,
      data: withdrawal,
      message: "Withdrawal request retrieved successfully"
    });
  } catch (error) {
    console.error("Get withdrawal by ID error:", error);
    res.status(500).json({
      success: false,
      message: error instanceof Error ? error.message : "Failed to retrieve withdrawal request"
    });
  }
};

